mapper.select:
select department_type_id, company_id, code, name, status, created_at, updated_at
from department_types
where department_type_id = #{departmentTypeId,jdbcType=VARCHAR}

mapper.update:
update department_types
code = #{code,jdbcType=VARCHAR}, name = #{name,jdbcType=VARCHAR}, status = #{status,jdbcType=VARCHAR}, updated_at = now()
where department_type_id = #{departmentTypeId,jdbcType=VARCHAR}

mapper.select:
select count(1)
from department_types
where company_id = #{companyId}

select count(1)
from department_types
where company_id = #{companyId}
  and code = #{code}

select count(1)
from department_types
where company_id = #{companyId}
  and code = #{code}
  and department_type_id <> #{departmentTypeId}

select count(1)
from department_types
where company_id = #{companyId}
  and name = #{name}

select count(1)
from department_types
where company_id = #{companyId}
  and name = #{name}
  and department_type_id <> #{departmentTypeId}

select department_type_id, company_id, code, name, status, created_at, updated_at
from department_types
where company_id = #{companyId}
  and status = #{status}
